class Solution:
    def getMinSwaps(self, num: str, k: int) -> int:
        def next_permutation(s):
            s = list(s)
            n = len(s)
            i = n - 2
            while i >= 0 and s[i] >= s[i + 1]:
                i -= 1
            if i < 0:
                return None
            j = n - 1
            while s[j] <= s[i]:
                j -= 1
            s[i], s[j] = s[j], s[i]
            s[i + 1:] = s[i + 1:][::-1]
            return ''.join(s)

        target = list(num)
        for _ in range(k):
            nxt = next_permutation(''.join(target))
            if nxt is None:
                break
            target = list(nxt)

        original = list(num)
        swaps = 0
        n = len(original)
        for i in range(n):
            if original[i] != target[i]:
                j = i + 1
                while j < n and original[j] != target[i]:
                    j += 1
                swaps += j - i
                while j > i:
                    original[j], original[j - 1] = original[j - 1], original[j]
                    j -= 1
        return swaps
```
efficiency: HIGH
time complexity: O(n * k)
space complexity: O(n)
